const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

function handleFileUpload(file, uploadDir = './uploads', options = {}) {
  return new Promise((resolve, reject) => {
    const {
      maxSize = 10 * 1024 * 1024,
      allowedExtensions = null,
      preserveOriginalName = false,
      createDirectory = true
    } = options;

    if (!file) {
      return reject(new Error('No file provided'));
    }

    if (file.size > maxSize) {
      return reject(new Error(`File size exceeds maximum allowed size of ${maxSize} bytes`));
    }

    const fileExtension = path.extname(file.name).toLowerCase();
    
    if (allowedExtensions && !allowedExtensions.includes(fileExtension)) {
      return reject(new Error(`File type ${fileExtension} not allowed`));
    }

    if (createDirectory && !fs.existsSync(uploadDir)) {
      fs.mkdirSync(uploadDir, { recursive: true });
    }

    const fileName = preserveOriginalName 
      ? file.name 
      : `${crypto.randomBytes(16).toString('hex')}${fileExtension}`;
    
    const filePath = path.join(uploadDir, fileName);

    const writeStream = fs.createWriteStream(filePath);

    writeStream.on('error', (error) => {
      reject(error);
    });

    writeStream.on('finish', () => {
      resolve({
        filename: fileName,
        path: filePath,
        size: file.size,
        mimetype: file.type || file.mimetype
      });
    });

    if (file.data) {
      writeStream.write(file.data);
      writeStream.end();
    } else if (file.path) {
      const readStream = fs.createReadStream(file.path);
      readStream.pipe(writeStream);
    } else {
      reject(new Error('Invalid file object'));
    }
  });
}

function handleMultipleFileUploads(files, uploadDir = './uploads', options = {}) {
  const uploadPromises = files.map(file => handleFileUpload(file, uploadDir, options));
  return Promise.all(uploadPromises);
}

